create function public.guard_project_owner_change()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if tg_op = 'UPDATE'
     and new.owner_profile_id is distinct from old.owner_profile_id
     and auth.uid() is not null
     and auth.uid() <> old.owner_profile_id then
    raise exception 'Only the current owner can transfer project ownership';
  end if;

  return new;
end;
$$;

create function public.handle_project_owner_membership()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  update public.project_members
  set role = 'co_owner'
  where project_id = new.id
    and role = 'owner'
    and profile_id <> new.owner_profile_id;

  insert into public.project_members (
    project_id,
    profile_id,
    role,
    ai_access,
    viewer_regime,
    credit_limit,
    used_credits
  )
  values (
    new.id,
    new.owner_profile_id,
    'owner',
    'project_pool',
    null,
    0,
    0
  )
  on conflict (project_id, profile_id) do update
    set role = 'owner',
        ai_access = case
          when public.project_members.ai_access = 'none' then 'project_pool'
          else public.project_members.ai_access
        end,
        viewer_regime = null;

  return new;
end;
$$;

create function public.enforce_project_member_owner_role()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_owner_profile_id uuid;
begin
  select p.owner_profile_id
  into v_owner_profile_id
  from public.projects p
  where p.id = new.project_id;

  if v_owner_profile_id is null then
    raise exception 'Project % not found while validating member role', new.project_id;
  end if;

  if (new.profile_id = v_owner_profile_id and new.role <> 'owner')
     or (new.profile_id <> v_owner_profile_id and new.role = 'owner') then
    raise exception 'Owner membership must stay aligned with projects.owner_profile_id';
  end if;

  return new;
end;
$$;

